using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;

namespace ProductReviewApplication.Controllers
{
    public class ProductReviewsController : Controller
    {
        private readonly ProductReviewContext _context;

        public ProductReviewsController(ProductReviewContext context)
        {
            _context = context;
        }

        public ActionResult Index(int productId)
        {
            var productReviews = _context.ProductReviews.Where(r => r.ProductId == productId).ToList();
            return View(productReviews);
        }
    }
}